 22→    public static int[] PlcValue = new int[10000];
 23→    public static int[] writePlcValue = new int[10000];
 24→    public static void SetPlc(int strAddress, int strData)
 25→    {
 26→        try
 27→        {
 28→            int address = strAddress;
 29→            string hexValue;
 30→
 31→            if (strData <= 0xFFFF) // 16비트
 32→            {
 33→                hexValue = strData.ToString("X4");
 34→                PLCData.writePlcValue[address] = Convert.ToUInt16(hexValue, 16);
 35→            }
 36→            else // 32비트
 37→            {
 38→                hexValue = strData.ToString("X8");
 39→                // 하위 워드 (뒤 4자리)
 40→                PLCData.writePlcValue[address] = Convert.ToUInt16(hexValue.Substring(4, 4), 16);
 41→                // 상위 워드 (앞 4자리)
 42→                PLCData.writePlcValue[address + 1] = Convert.ToUInt16(hexValue.Substring(0, 4), 16);
 43→            }
 44→        }
 45→        catch (Exception ex)
 46→        {
 47→            //Logger.Log("PLC 데이터 변환 오류: " + ex.Message);
 48→        }
 49→    }
