158→    public static double TryGetDouble(IniFile ini, string section, string key, double defaultValue = 0.0)
159→    {
160→        string valueStr = ini.ReadValue(section, key);
161→
162→        if (string.IsNullOrWhiteSpace(valueStr))
163→        {
164→            // 값이 없으면 기본값 0 저장
165→            ini.WriteValue(section, key, "0");
166→            return 0.0;
167→        }
168→
169→        if (double.TryParse(valueStr, out double result))
170→        {
171→            return result;
172→        }
173→
174→        // 숫자 변환 실패 시도 → 0으로 저장
175→        //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
176→        ini.WriteValue(section, key, "0");
177→        return 0.0;
178→    }
179→    public static int TryGetInt(IniFile ini, string section, string key, int defaultValue = 0)
180→    {
181→        string valueStr = ini.ReadValue(section, key);
182→
