186→            ini.WriteValue(section, key, defaultValue.ToString());
187→            return defaultValue;
188→        }
189→
190→        if (int.TryParse(valueStr, out int result))
191→        {
192→            return result;
193→        }
194→
195→        // 숫자 변환 실패 → 기본값으로 저장
196→        ini.WriteValue(section, key, defaultValue.ToString());
197→        return defaultValue;
198→    }
