171→        // ===== 출력 제어 =====
172→        public void Do_On(int bit)
173→        {
174→            if ((uint)bit >= 64u)
175→            {
176→                return;
177→            }
178→
179→            lock (_outLock)
180→            {
181→                if (!_out[bit])
182→                {
183→                    _out[bit] = true;
184→                    _outDirty = true;
185→                    _outVersion++;
186→                }
187→            }
188→        }
