190→        public void Do_Off(int bit)
191→        {
192→            if ((uint)bit >= 64u)
193→            {
194→                return;
195→            }
196→
197→            lock (_outLock)
198→            {
199→                if (_out[bit])
200→                {
201→                    _out[bit] = false;
202→                    _outDirty = true;
203→                    _outVersion++;
204→                }
205→            }
206→        }
