208→        // 같은 값이어도 재전송이 필요할 때(옵션)
209→        public void Do_On_Force(int bit)
210→        {
211→            if ((uint)bit >= 64u)
212→            {
213→                return;
214→            }
215→
216→            lock (_outLock)
217→            {
218→                _out[bit] = true;
219→                _outDirty = true;
220→                _outVersion++;
221→            }
222→        }
