239→        // 즉시 쓰기 단계로 진입시키는 트리거
240→        public void Commit()
241→        {
242→            // ★ 버전 증가로 "이 이후 변경이 반영되어야 한다"는 사실을 남긴다.
243→            lock (_outLock)
244→            {
245→                _outDirty = true;
246→                _outVersion++;
247→            }
248→
249→            if (!_waiting)
250→            {
251→                _step = 4; // 다음 루프에서 W OUT0 → W OUT1
252→            }
253→        }
