288→        // ===== 워커 루프 (상태머신) =====
289→        private void WorkLoop()
290→        {
291→            while (_running)
292→            {
293→                try
294→                {
295→                    // 타임아웃 감시
296→                    if (_waiting && _awaitSw.IsRunning && _awaitSw.ElapsedMilliseconds > ResponseTimeoutMs)
297→                    {
298→                        _consecutiveTimeouts++;
299→                        LogInfo("[TIMEOUT " + _consecutiveTimeouts + "] step=" + _step + " → reset");
300→                        SoftReset();
301→
302→                        if (_consecutiveTimeouts >= ReopenOnTimeoutCount)
303→                        {
304→                            ReopenPort();
305→                            _consecutiveTimeouts = 0;
306→                        }
307→                    }
308→
309→                    if (!_waiting)
310→                    {
311→                        switch (_step)
312→                        {
313→                            case 0:
314→                                SendRead(ADR_IN0, CNT_32);
315→                                Await();
316→                                _step = 1;
317→                                break;
318→
319→                            case 2:
320→                                SendRead(ADR_IN1, CNT_32);
321→                                Await();
322→                                _step = 3;
323→                                break;
324→
325→                            case 4:
326→                                if (_outDirty)
327→                                {
328→                                    // ★ 현재 쓰기 사이클이 반영해야 할 버전 스냅샷
329→                                    lock (_outLock)
330→                                    {
331→                                        _writeCycleVersion = _outVersion;
332→                                    }
333→
334→                                    SendWrite(ADR_OUT0, 0);
335→                                    Await();
336→                                    _step = 5;
337→                                }
338→                                else
339→                                {
340→                                    _step = 6;
341→                                }
342→                                break;
343→
344→                            case 6:
345→                                if (_outDirty)
346→                                {
347→                                    SendWrite(ADR_OUT1, 32);
348→                                    Await();
349→                                    _step = 7;
350→                                }
351→                                else
352→                                {
353→                                    _step = 0;
354→                                }
355→                                break;
356→                        }
357→                    }
358→                }
359→                catch (Exception ex)
360→                {
361→                    LogInfo("[ERR] Work: " + ex.Message);
362→                    SoftReset();
363→                }
364→
365→                Thread.Sleep(PollDelayMs);
366→            }
367→        }
