369→        // ===== 수신 스레드 =====
370→        private void ReadLoop()
371→        {
372→            var buf = new byte[2048];
373→
374→            while (_running)
375→            {
376→                try
377→                {
378→                    int n = _port.BaseStream.Read(buf, 0, buf.Length); // blocking
379→
380→                    if (n > 0)
381→                    {
382→                        AppendRx(buf, n);
383→                        ProcessFrames();
384→                    }
385→                }
386→                catch (TimeoutException)
387→                {
388→                    // ignore
389→                }
390→                catch (Exception ex)
391→                {
392→                    LogInfo("[ERR] Read: " + ex.Message);
393→                    Thread.Sleep(10);
394→                }
395→            }
396→        }
