398→        // ===== RX 누적/프레임 처리 =====
399→        private void AppendRx(byte[] src, int len)
400→        {
401→            lock (_rxLock)
402→            {
403→                if (_rxAccumLen + len > _rxAccum.Length)
404→                {
405→                    var bigger = new byte[Math.Max(_rxAccum.Length * 2, _rxAccumLen + len)];
406→                    Buffer.BlockCopy(_rxAccum, 0, bigger, 0, _rxAccumLen);
407→                    _rxAccum = bigger;
408→                }
409→
410→                Buffer.BlockCopy(src, 0, _rxAccum, _rxAccumLen, len);
411→                _rxAccumLen += len;
412→            }
413→        }
414→
415→        private void ProcessFrames()
416→        {
417→            while (true)
418→            {
419→                int etxIndex;
420→
421→                lock (_rxLock)
422→                {
423→                    etxIndex = IndexOf(_rxAccum, 0, _rxAccumLen, ETX);
424→                    if (etxIndex < 0)
425→                    {
426→                        return;
427→                    }
428→                }
429→
430→                string frame;
431→
432→                lock (_rxLock)
433→                {
434→                    frame = Encoding.ASCII.GetString(_rxAccum, 0, etxIndex + 1); // ETX 포함
435→                    int remain = _rxAccumLen - (etxIndex + 1);
436→
437→                    if (remain > 0)
438→                    {
439→                        Buffer.BlockCopy(_rxAccum, etxIndex + 1, _rxAccum, 0, remain);
440→                    }
441→
442→                    _rxAccumLen = remain;
443→                }
444→
445→                if (EnableLog && VerboseTxRx)
446→                {
447→                    //Log("RX " + frame);
448→                }
449→
450→                if (!_waiting)
451→                {
452→                    continue; // 예상 응답이 아닐 때는 무시(필요시 큐잉)
453→                }
454→
455→                try
456→                {
457→                    switch (_step)
458→                    {
459→                        case 1: // IN0 응답
460→                            if (!TryParseInputs(frame, 0))
461→                            {
462→                                //LogInfo("[WARN] IN0 parse fail");
463→                            }
464→                            _step = 2;
465→                            break;
466→
467→                        case 3: // IN1 응답
468→                            if (!TryParseInputs(frame, 32))
469→                            {
470→                                //LogInfo("[WARN] IN1 parse fail");
471→                            }
472→                            _step = 4;
473→                            break;
474→
475→                        case 5: // OUT0 ack
476→                            _step = 6;
477→                            break;
478→
479→                        case 7: // OUT1 ack
480→                            // ★ 쓰기 사이클 시작 시점의 버전과 현재 버전이 같을 때만 Dirty 클리어
481→                            lock (_outLock)
482→                            {
483→                                if (_writeCycleVersion == _outVersion)
484→                                {
485→                                    _outDirty = false;
486→                                }
487→                                // 다르면: 사이클 도중에 Commit이 한 번 더 들어왔다는 뜻 → Dirty 유지
488→                            }
489→                            _step = 0;
490→                            break;
491→                    }
492→                }
493→                finally
494→                {
495→                    ResetAwait();
496→                    _consecutiveTimeouts = 0;
497→                }
498→            }
499→        }
