501→        // ===== 파서 =====
502→        // 고정 오프셋(11) 시도 → 부족하면 끝쪽에서 128자리(32*4) 숫자 블록 추출
503→        private bool TryParseInputs(string frame, int dstOffset)
504→        {
505→            int ok = 0;
506→
507→            // 1) 고정 오프셋(과거 동작과 동일)
508→            for (int i = 0; i < 32; i++)
509→            {
510→                int pos = 11 + i * 4;
511→                if (pos + 4 > frame.Length)
512→                {
513→                    break;
514→                }
515→
516→                int val;
517→                if (int.TryParse(frame.Substring(pos, 4), out val))
518→                {
519→                    _in[dstOffset + i] = (val != 0);
520→                    ok++;
521→                }
522→                else
523→                {
524→                    break;
525→                }
526→            }
527→
528→            if (ok >= 28)
529→            {
530→                return true; // 대부분 맞으면 통과
531→            }
532→
533→            // 2) 후방 탐색: 끝에서부터 숫자 연속 구간 중 128자리 이상 찾기
534→            int tailStart = FindTailDigitRun(frame, 128);
535→            if (tailStart >= 0)
536→            {
537→                int parsed = 0;
538→                int end = frame.Length;
539→
540→                for (int i = 0; i < 32; i++)
541→                {
542→                    int s = end - 4 * (32 - i);
543→                    if (s < tailStart)
544→                    {
545→                        break;
546→                    }
547→
548→                    int v;
549→                    if (int.TryParse(frame.Substring(s, 4), out v))
550→                    {
551→                        _in[dstOffset + i] = (v != 0);
552→                        parsed++;
553→                    }
554→                }
555→
556→                return parsed == 32;
557→            }
558→
559→            return false;
560→        }
561→
562→        private static int FindTailDigitRun(string s, int minLen)
563→        {
564→            int run = 0;
565→
566→            for (int i = s.Length - 1; i >= 0; i--)
567→            {
568→                if (char.IsDigit(s[i]))
569→                {
570→                    run++;
571→                }
572→                else
573→                {
574→                    if (run >= minLen)
575→                    {
576→                        return i + 1;
577→                    }
578→
579→                    run = 0;
580→                }
581→            }
582→
583→            if (run >= minLen)
584→            {
585→                return 0;
586→            }
587→
588→            return -1;
589→        }
