591→        private static int IndexOf(byte[] buf, int start, int len, byte val)
592→        {
593→            int end = start + len;
594→
595→            for (int i = start; i < end; i++)
596→            {
597→                if (buf[i] == val)
598→                {
599→                    return i;
600→                }
601→            }
602→
603→            return -1;
604→        }
