606→        // ===== 송신 =====
607→        private void SendRead(string addr, string countHex)
608→        {
609→            byte[] a = Encoding.ASCII.GetBytes(addr);
610→            byte[] c = Encoding.ASCII.GetBytes(countHex);
611→
612→            byte[] pkt = new byte[1 + 3 + 2 + 2 + a.Length + c.Length + 1];
613→            int p = 0;
614→
615→            pkt[p++] = ENQ;
616→            pkt[p++] = (byte)'0';
617→            pkt[p++] = (byte)'0';
618→            pkt[p++] = (byte)'R';
619→            pkt[p++] = (byte)'S';
620→            pkt[p++] = (byte)'B';
621→            pkt[p++] = (byte)'0';
622→            pkt[p++] = (byte)'7';
623→            Buffer.BlockCopy(a, 0, pkt, p, a.Length);
624→            p += a.Length;
625→            Buffer.BlockCopy(c, 0, pkt, p, c.Length);
626→            p += c.Length;
627→            pkt[p++] = EOT;
628→
629→            lock (_txLock)
630→            {
631→                _port.Write(pkt, 0, pkt.Length);
632→            }
633→
634→            //LogTx("TX R " + addr);
635→        }
636→
637→        private void SendWrite(string addr, int outOffset)
638→        {
639→            // 스냅샷으로 페이로드 생성(경쟁조건 방지)
640→            bool[] snap = new bool[32];
641→
642→            lock (_outLock)
643→            {
644→                Array.Copy(_out, outOffset, snap, 0, 32);
645→            }
646→
647→            byte[] payload = new byte[128];
648→            int k = 0;
649→
650→            for (int i = 0; i < 32; i++)
651→            {
652→                bool on = snap[i];
653→                payload[k++] = (byte)'0';
654→                payload[k++] = (byte)'0';
655→                payload[k++] = (byte)'0';
656→                payload[k++] = on ? (byte)'1' : (byte)'0';
657→            }
658→
659→            byte[] a = Encoding.ASCII.GetBytes(addr);
660→            byte[] c = Encoding.ASCII.GetBytes(CNT_32);
661→
662→            byte[] pkt = new byte[1 + 3 + 2 + 2 + a.Length + c.Length + payload.Length + 1];
663→            int p = 0;
664→
665→            pkt[p++] = ENQ;
666→            pkt[p++] = (byte)'0';
667→            pkt[p++] = (byte)'0';
668→            pkt[p++] = (byte)'W';
669→            pkt[p++] = (byte)'S';
670→            pkt[p++] = (byte)'B';
671→            pkt[p++] = (byte)'0';
672→            pkt[p++] = (byte)'7';
673→            Buffer.BlockCopy(a, 0, pkt, p, a.Length);
674→            p += a.Length;
675→            Buffer.BlockCopy(c, 0, pkt, p, c.Length);
676→            p += c.Length;
677→            Buffer.BlockCopy(payload, 0, pkt, p, payload.Length);
678→            p += payload.Length;
679→            pkt[p++] = EOT;
680→
681→            lock (_txLock)
682→            {
683→                _port.Write(pkt, 0, pkt.Length);
684→            }
685→
686→            //LogTx("TX W " + addr);
687→        }
