  8→public sealed class Ri20wStandard : IDisposable
  9→{
 10→    private readonly SerialPort _port;
 11→    private readonly Action<string> _log;
 12→    private Thread _rxThread;
 13→    private volatile bool _running;
 14→
 15→    private int _frameCount = 0;
 16→    private DateTime _lastFpsLogTime = DateTime.UtcNow;
 17→    private DateTime _lastResponseTime = DateTime.UtcNow;
 18→
 19→    public bool EnableLog { get; set; } = false;
 20→    public int DeviceId { get; }
 21→
 22→    // ✅ 최신값 (숫자 + 단위)
 23→    public double Value = double.NaN;
 24→    public string Unit = "";
 25→
 26→    // 이벤트
 27→    public event Action<double, string> ValueReceived; // (값, 단위)
 28→    public event Action<string> RawReceived;          // 원문
 29→
 30→    private static readonly Regex NumUnitRegex = new Regex(
 31→        @"([+-]?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)([A-Za-z%µ]*)",
 32→        RegexOptions.Compiled | RegexOptions.CultureInvariant
 33→    );
 34→
 35→    public Ri20wStandard(string portName, int deviceId = 1, Action<string> logger = null)
 36→    {
 37→        if (deviceId < 1 || deviceId > 99)
 38→            throw new ArgumentOutOfRangeException(nameof(deviceId), "DeviceId는 1~99");
 39→
 40→        DeviceId = deviceId;
 41→        _log = logger;
 42→
 43→        _port = new SerialPort(portName, 57600, Parity.None, 8, StopBits.One)
 44→        {
 45→            Encoding = Encoding.ASCII,
 46→            NewLine = "\r\n",
 47→            ReadTimeout = 50,
 48→            WriteTimeout = 50
 49→        };
 50→    }
 51→
 52→    public void Start()
 53→    {
 54→        if (_running) return;
 55→
 56→        try
 57→        {
 58→            if (!_port.IsOpen)
 59→                _port.Open();
 60→        }
 61→        catch (Exception ex)
 62→        {
 63→            Log($"RI-20W[{DeviceId:D2}] 포트 열기 실패: {ex.Message}");
 64→            return; // 실행은 계속, 장비는 미시작 상태
 65→        }
 66→
 67→        _running = true;
 68→        _lastResponseTime = DateTime.UtcNow; // 응답 시간 초기화
 69→        _rxThread = new Thread(ReadLoop) { IsBackground = true };
 70→        _rxThread.Start();
 71→        Log($"RI-20W[{DeviceId:D2}] 시작 (57600bps)");
 72→
 73→        RequestValue(); // 최초 트리거
 74→    }
 75→
 76→
 77→    public void Stop()
 78→    {
 79→        _running = false;
 80→        // 스레드 종료 대기 (포트는 닫지 않음)
 81→        if (_rxThread != null && _rxThread.IsAlive)
 82→        {
 83→            _rxThread.Join(100); // 최대 100ms 대기
 84→        }
 85→        Log($"RI-20W[{DeviceId:D2}] 통신 중지");
 86→    }
 87→    
 88→    public void Close()
 89→    {
 90→        Stop();
 91→        try { if (_port.IsOpen) _port.Close(); } catch { }
 92→    }
 93→
 94→    public void Dispose() => Close();
 95→
 96→    private void ReadLoop()
 97→    {
 98→        var sb = new StringBuilder(256);
 99→
100→        try
101→        {
102→            while (_running && _port.IsOpen)
103→            {
104→                string chunk = _port.ReadExisting();
105→                if (chunk.Length > 0)
106→                {
107→                    sb.Append(chunk);
108→                    int idx;
109→                    while ((idx = sb.ToString().IndexOf("\r\n", StringComparison.Ordinal)) >= 0)
110→                    {
111→                        string line = sb.ToString(0, idx).Trim();
112→                        sb.Remove(0, idx + 2);
113→                        if (line.Length == 0) continue;
114→                        ParseLine(line);
115→                    }
116→                }
117→                else
118→                {
119→                    if ((DateTime.UtcNow - _lastResponseTime).TotalSeconds > 1.0)
120→                    {
121→                        Log($"경고: ID{DeviceId:D2} 1초 이상 응답 없음 → 재요청");
122→                        RequestValue();
123→                        _lastResponseTime = DateTime.UtcNow;
124→                    }
125→                    Thread.Sleep(1);
126→                }
127→            }
128→        }
129→        catch (Exception ex)
130→        {
131→            Log($"수신 오류(ID{DeviceId:D2}): {ex.Message}");
132→        }
133→    }
134→
135→    private void ParseLine(string line)
136→    {
137→        RawReceived?.Invoke(line);
138→
139→        _frameCount++;
140→        var now = DateTime.UtcNow;
141→        if ((now - _lastFpsLogTime).TotalSeconds >= 1.0)
142→        {
143→            //Log($"RX ID{DeviceId:D2}: {_frameCount} frames/sec");
144→            _frameCount = 0;
145→            _lastFpsLogTime = now;
146→        }
147→
148→        // 표준 응답 예: "ID,01,+00123.4kg"
149→        string[] parts = line.Split(',');
150→        if (parts.Length >= 3)
151→        {
152→            string valStr = parts[2].Trim();
153→            var match = NumUnitRegex.Match(valStr);
154→            if (match.Success)
155→            {
156→                if (double.TryParse(match.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double val))
157→                {
158→                    string unit = match.Groups[2].Value;
159→                    Value = val;
160→                    Unit = unit;
161→                    ValueReceived?.Invoke(val, unit);
162→                }
163→            }
164→        }
165→
166→        _lastResponseTime = now;
167→        if (_running) RequestValue();
168→    }
169→
170→    public void RequestValue()
171→    {
172→        if (!_port.IsOpen) return;
173→        string cmd = $"ID{DeviceId:D2}P\r\n";
174→        _port.Write(cmd);
175→        //Log("TX: " + cmd.Trim());
176→    }
177→
178→    public void SetZero()
179→    {
180→        if (!_port.IsOpen) return;
181→        string cmd = $"ID{DeviceId:D2}Z\r\n";
182→        _port.Write(cmd);
183→        Value = double.NaN; // 제로 명령 후 NaN으로 설정 (응답 대기 상태)
184→        //Log("TX: " + cmd.Trim());
185→    }
186→
187→    private void Log(string s)
188→    {
189→        if (EnableLog && _log != null)
190→            _log(s);
191→    }
192→}
