  1→using System;
  2→using System.Diagnostics;
  3→using System.Globalization;
  4→using System.IO.Ports;
  5→using System.Text;
  6→using System.Windows.Forms;
  7→
  8→public sealed class SupplyController : IDisposable
  9→{
 10→    public enum MeasureMode
 11→    {
 12→        ModeA, // 전류만 측정
 13→        ModeB  // 전압 + 전류 측정 (기존)
 14→    }
 15→
 16→    // --- 외부 주입/설정 ---
 17→    private readonly SerialPort _port;
 18→    private readonly Timer _timer;
 19→    private readonly object _lock = new object();
 20→
 21→    // 스텝: 0 시작 → VOLT? 또는 CURR? 요청, 1 VOLT 응답 대기,
 22→    //       2 CURR? 요청, 3 CURR 응답 대기, 4 전압 설정 후 0으로
 23→    private int _step = 0;
 24→
 25→    // 수신 버퍼
 26→    private readonly StringBuilder _rx = new StringBuilder(256);
 27→
 28→    // 타임아웃 측정
 29→    private readonly Stopwatch _awaitSw = new Stopwatch();
 30→    public int ResponseTimeoutMs { get; set; } = 2000;
 31→
 32→    // 모드 (외부에서 설정)
 33→    public MeasureMode Mode { get; set; } = MeasureMode.ModeB;
 34→
 35→    // 공개 값
 36→    public double ValueVolt { get; private set; }
 37→    public double ValueCurr { get; private set; }
 38→    public double TargetVolt { get; set; } = 13.5;
 39→
 40→    // 로그 훅(선택) — 람다 금지, 기본 no-op
 41→    private Action<string> _log;
 42→    public Action<string> Log
 43→    {
 44→        get { return _log; }
 45→        set { _log = value ?? NoopLog; }
 46→    }
 47→    private void NoopLog(string s) { }
 48→
 49→    public bool IsRunning { get { return _timer.Enabled; } }
 50→
 51→    // 최초 연결 후 *ADR 1 1회 송신 제어
 52→    private bool _adrSent;      // 이번 연결 세션에서 이미 송신했는가
 53→    private bool _adrPending;   // Open 직후 타이머 틱에서 보낼 것인가
 54→
 55→    // Open 후 ADR 보내기 전 대기(ms). 일부 장비는 안정화 필요.
 56→    public int PostOpenAdrDelayMs { get; set; } = 50;
 57→    private int _adrDelayRemainMs;
 58→
 59→    public SupplyController(SerialPort port, int pollIntervalMs = 100)
 60→    {
 61→        if (port == null) throw new ArgumentNullException("port");
 62→        _port = port;
 63→
 64→        // SCPI가 CR로 라인 종료하는 장비 가정
 65→        _port.NewLine = "\r";
 66→        if (_port.Encoding == null) _port.Encoding = Encoding.ASCII;
 67→
 68→        _port.DataReceived += OnDataReceived;
 69→
 70→        _timer = new Timer();
 71→        _timer.Interval = pollIntervalMs;
 72→        _timer.Tick += OnTick;
 73→
 74→        _log = NoopLog;
 75→    }
 76→
 77→    public void Start()
 78→    {
 79→        if (!_port.IsOpen)
 80→        {
 81→            try
 82→            {
 83→                _port.Open();
 84→                Log("Serial Opened: " + _port.PortName);
 85→
 86→                // 새 연결 세션: ADR 1회 송신 예약
 87→                _adrSent = false;
 88→                _adrPending = true;
 89→                _adrDelayRemainMs = PostOpenAdrDelayMs;
 90→            }
 91→            catch (Exception ex)
 92→            {
 93→                Log("[ERR] Open failed: " + ex.Message);
 94→                return;
 95→            }
 96→        }
 97→        else
 98→        {
 99→            // 이미 열려 있던 경우에는 사용자 의도에 맞게 한 번 더 보낼지 결정.
100→            // 기본: 열려 있던 세션에서는 보내지 않음.
101→            // 필요 시 외부에서 _adrSent=false; _adrPending=true; 로 재설정하면 됨.
102→        }
103→
104→        _step = 0;
105→        _awaitSw.Reset();
106→        _timer.Start();
107→        Log("SupplyController started.");
108→    }
109→
110→    public void Stop()
111→    {
112→        _timer.Stop();
113→        _awaitSw.Reset();
114→        Log("SupplyController stopped.");
115→    }
116→
117→    public void Dispose()
118→    {
119→        try
120→        {
121→            _timer.Stop();
122→            _timer.Tick -= OnTick;
123→            _port.DataReceived -= OnDataReceived;
124→        }
125→        catch { }
126→    }
127→
128→    // --- 100ms 폴링 스텝 머신 ---
129→    private void OnTick(object sender, EventArgs e)
130→    {
131→        try
132→        {
133→            if (!_port.IsOpen) return;
134→
135→            // 1) Open 직후 1회만 *ADR 1 송신
136→            if (_adrPending && !_adrSent)
137→            {
138→                // 간단한 지연 처리 (타이머 간격 기준 누적)
139→                _adrDelayRemainMs -= _timer.Interval;
140→                if (_adrDelayRemainMs <= 0)
141→                {
142→                    WriteLineSafe("*ADR 1");
143→                    _adrSent = true;
144→                    _adrPending = false;
145→                    Log("[INIT] *ADR 1 sent once after open.");
146→                }
147→                // ADR 처리 중에는 본 루프 진행 안 하고 다음 틱에서 계측 시작
148→                return;
149→            }
150→
151→            // 2) 응답 대기 상태(1, 3)에서 타임아웃 체크
152→            if ((_step == 1 || _step == 3) && _awaitSw.IsRunning)
153→            {
154→                if (_awaitSw.ElapsedMilliseconds > ResponseTimeoutMs)
155→                {
156→                    ResetState("No response within " + ResponseTimeoutMs + " ms (step=" + _step + ")");
157→                    return;
158→                }
159→            }
160→
161→            // 3) 측정/설정 스텝
162→            switch (_step)
163→            {
164→                case 0:
165→                    if (Mode == MeasureMode.ModeA)
166→                    {
167→                        WriteLineSafe("MEAS:CURR?");
168→                        _step = 3;
169→                        _awaitSw.Restart();
170→                    }
171→                    else
172→                    {
173→                        WriteLineSafe("MEAS:VOLT?");
174→                        _step = 1;
175→                        _awaitSw.Restart();
176→                    }
177→                    break;
178→
179→                case 1: // VOLT 응답 대기
180→                    break;
181→
182→                case 2: // CURR? 요청
183→                    WriteLineSafe("MEAS:CURR?");
184→                    _step = 3;
185→                    _awaitSw.Restart();
186→                    break;
187→
188→                case 3: // CURR 응답 대기
189→                    break;
190→
191→                case 4: // 전압 설정
192→                    WriteLineSafe("SOUR:VOLT " + TargetVolt.ToString("0.###", CultureInfo.InvariantCulture));
193→                    _step = 0;
194→                    _awaitSw.Reset();
195→                    break;
196→            }
197→        }
198→        catch (Exception ex)
199→        {
200→            Log("[ERR] Tick: " + ex.Message);
201→        }
202→    }
203→
204→    // --- 수신 처리 (백그라운드 스레드) ---
205→    private void OnDataReceived(object sender, SerialDataReceivedEventArgs e)
206→    {
207→        try
208→        {
209→            string chunk = _port.ReadExisting();
210→            if (string.IsNullOrEmpty(chunk)) return;
211→
212→            lock (_lock)
213→            {
214→                _rx.Append(chunk);
215→
216→                // CR 기준 라인 파싱
217→                while (true)
218→                {
219→                    int cr = _rx.ToString().IndexOf('\r');
220→                    if (cr < 0) break;
221→
222→                    string line = _rx.ToString(0, cr);
223→                    _rx.Remove(0, cr + 1);
224→
225→                    HandleLine(line.Trim());
226→                }
227→            }
228→        }
229→        catch (Exception ex)
230→        {
231→            Log("[ERR] RX: " + ex.Message);
232→        }
233→    }
234→
235→    private void HandleLine(string line)
236→    {
237→        if (string.IsNullOrWhiteSpace(line)) return;
238→
239→        if (_step == 1) // VOLT 응답
240→        {
241→            double v;
242→            if (TryParseDouble(line, out v))
243→            {
244→                ValueVolt = v;
245→                _awaitSw.Reset();
246→                _step = 2; // 전류 요청 단계
247→            }
248→            return;
249→        }
250→
251→        if (_step == 3) // CURR 응답
252→        {
253→            double a;
254→            if (TryParseDouble(line, out a))
255→            {
256→                ValueCurr = a;
257→                _awaitSw.Reset();
258→
259→                if (Mode == MeasureMode.ModeA)
260→                    _step = 0; // 바로 반복
261→                else
262→                    _step = 4; // 전압 설정
263→            }
264→            return;
265→        }
266→    }
267→
268→    private static bool TryParseDouble(string s, out double value)
269→    {
270→        return double.TryParse(s, NumberStyles.Float, CultureInfo.InvariantCulture, out value);
271→    }
272→
273→    private void WriteLineSafe(string cmd)
274→    {
275→        if (!_port.IsOpen) return;
276→        _port.Write(cmd);
277→        _port.Write(_port.NewLine);
278→    }
279→
280→    private void ResetState(string reason)
281→    {
282→        try
283→        {
284→            _awaitSw.Reset();
285→            _step = 0;
286→            lock (_lock) { _rx.Clear(); }
287→            try { _port.DiscardInBuffer(); } catch (Exception ex) { Log($"[WARN] DiscardInBuffer 실패: {ex.Message}"); }
288→            Log("[TIMEOUT] " + reason + ". State reset (step=0).");
289→        }
290→        catch (Exception ex)
291→        {
292→            Log("[ERR] ResetState: " + ex.Message);
293→        }
294→    }
295→
296→    // --- 유틸: 외부에서 재연결 시 ADR 재송신을 원할 때 호출 ---
297→    public void RequestAdrResendOnNextTick()
298→    {
299→        if (_port.IsOpen)
300→        {
301→            _adrSent = false;
302→            _adrPending = true;
303→            _adrDelayRemainMs = PostOpenAdrDelayMs;
304→        }
305→    }
306→}
