  1→using System;
  2→using System.IO.Ports;
  3→using NoiseTest_WPF.Classes;
  4→
  5→namespace NoiseTest_WPF.Hardware
  6→{
  7→    /// <summary>
  8→    /// 레이저 거리 센서 - Keyence RS232 통신용 (미사용, 백업용)
  9→    /// 명령어: "MS\r\n" 전송 → 거리값 응답
 10→    /// </summary>
 11→    public class LaserSensorKeyenceRS232 : IDisposable
 12→    {
 13→        private SerialPort _serialPort;
 14→        private bool _disposed = false;
 15→        private double _lastValue = 0;
 16→        private readonly object _lock = new object();
 17→
 18→        public bool IsOpen => _serialPort?.IsOpen ?? false;
 19→        public double LastValue => _lastValue;
 20→
 21→        public event EventHandler<double> DataReceived;
 22→
 23→        public LaserSensorKeyenceRS232()
 24→        {
 25→        }
 26→
 27→        /// <summary>
 28→        /// 포트 열기
 29→        /// </summary>
 30→        public bool Open(string portName, int baudRate = 9600)
 31→        {
 32→            try
 33→            {
 34→                Close();
 35→
 36→                _serialPort = new SerialPort(portName, baudRate, Parity.None, 8, StopBits.One)
 37→                {
 38→                    ReadTimeout = 500,
 39→                    WriteTimeout = 500,
 40→                    NewLine = "\r\n"
 41→                };
 42→
 43→                _serialPort.DataReceived += SerialPort_DataReceived;
 44→                _serialPort.Open();
 45→
 46→                return true;
 47→            }
 48→            catch (Exception ex)
 49→            {
 50→                System.Diagnostics.Debug.WriteLine($"LaserSensorKeyence Open Error: {ex.Message}");
 51→                return false;
 52→            }
 53→        }
 54→
 55→        /// <summary>
 56→        /// 시스템 설정에서 포트 정보 로드 후 열기
 57→        /// </summary>
 58→        public bool OpenFromSettings()
 59→        {
 60→            var portName = SystemSetting.Get("COM_Laser", "");
 61→            var baudRate = SystemSetting.Get("COM_Laser_Baud", "9600");
 62→
 63→            if (string.IsNullOrEmpty(portName))
 64→                return false;
 65→
 66→            return Open(portName, int.Parse(baudRate));
 67→        }
 68→
 69→        /// <summary>
 70→        /// 포트 닫기
 71→        /// </summary>
 72→        public void Close()
 73→        {
 74→            if (_serialPort != null)
 75→            {
 76→                if (_serialPort.IsOpen)
 77→                {
 78→                    try
 79→                    {
 80→                        _serialPort.DataReceived -= SerialPort_DataReceived;
 81→                        _serialPort.Close();
 82→                    }
 83→                    catch { }
 84→                }
 85→                _serialPort.Dispose();
 86→                _serialPort = null;
 87→            }
 88→        }
 89→
 90→        /// <summary>
 91→        /// 측정 요청 (폴링 방식)
 92→        /// </summary>
 93→        public void RequestMeasurement()
 94→        {
 95→            if (_serialPort?.IsOpen == true)
 96→            {
 97→                try
 98→                {
 99→                    _serialPort.Write("MS\r\n");
100→                }
101→                catch (Exception ex)
102→                {
103→                    System.Diagnostics.Debug.WriteLine($"LaserSensorKeyence Write Error: {ex.Message}");
104→                }
105→            }
106→        }
107→
108→        private void SerialPort_DataReceived(object sender, SerialDataReceivedEventArgs e)
109→        {
110→            try
111→            {
112→                var incoming = _serialPort.ReadLine();
113→                if (string.IsNullOrEmpty(incoming))
114→                    return;
115→
116→                _serialPort.DiscardInBuffer();
117→
118→                // 응답 파싱 (콤마 구분 데이터의 첫번째 값 사용)
119→                var parts = incoming.Trim().Split(',');
120→                if (parts.Length > 0 && double.TryParse(parts[0], out double value))
121→                {
122→                    lock (_lock)
123→                    {
124→                        _lastValue = value;
125→                    }
126→                    DataReceived?.Invoke(this, value);
127→                }
128→            }
129→            catch (Exception ex)
130→            {
131→                System.Diagnostics.Debug.WriteLine($"LaserSensorKeyence Read Error: {ex.Message}");
132→            }
133→        }
134→
135→        public void Dispose()
136→        {
137→            if (!_disposed)
138→            {
139→                Close();
140→                _disposed = true;
141→            }
142→        }
143→    }
144→}
