  1→using System;
  2→using System.IO.Ports;
  3→
  4→namespace NoiseTest_WPF.Hardware
  5→{
  6→    /// <summary>
  7→    /// LVDT 거리센서 시리얼 통신 클래스 (RI 시리즈 디지털 인디케이터)
  8→    /// - 9600 baud, 8N1
  9→    /// - DataReceived 이벤트로 수신 (포트별 독립 ThreadPool 쓰레드)
 10→    /// - RI 시리즈 Standard 프로토콜 Stream 모드 (F-40=000, F-42=0)
 11→    /// - 수신 데이터 형식: "ST,NT,+01234.5\r\n" (16바이트)
 12→    /// </summary>
 13→    public class LvdtSensor : IDisposable
 14→    {
 15→        private SerialPort _port;
 16→        private string _name;
 17→        private bool _disposed;
 18→        private readonly object _valueLock = new object();
 19→        private double _value;
 20→        private string _receiveBuffer = "";
 21→
 22→        /// <summary>
 23→        /// 현재 측정값 (mm, 부호 포함)
 24→        /// </summary>
 25→        public double Value
 26→        {
 27→            get { lock (_valueLock) return _value; }
 28→            private set { lock (_valueLock) _value = value; }
 29→        }
 30→
 31→        /// <summary>
 32→        /// 센서 에러 상태 (ER 수신 시 true)
 33→        /// </summary>
 34→        public bool IsError { get; private set; }
 35→
 36→        /// <summary>
 37→        /// 포트 열림 상태
 38→        /// </summary>
 39→        public bool IsOpen => _port?.IsOpen ?? false;
 40→
 41→        /// <summary>
 42→        /// 센서 이름 (LVDT1~LVDT4)
 43→        /// </summary>
 44→        public string Name => _name;
 45→
 46→        /// <summary>
 47→        /// 로그 콜백
 48→        /// </summary>
 49→        public Action<string> Log { get; set; }
 50→
 51→        public LvdtSensor(string name)
 52→        {
 53→            _name = name;
 54→        }
 55→
 56→        /// <summary>
 57→        /// 시리얼 포트 열기
 58→        /// </summary>
 59→        public bool Open(string portName, int baudRate = 9600)
 60→        {
 61→            try
 62→            {
 63→                if (_port != null && _port.IsOpen)
 64→                    _port.Close();
 65→
 66→                _port = new SerialPort(portName, baudRate, Parity.None, 8, StopBits.One)
 67→                {
 68→                    ReadTimeout = 500,
 69→                    WriteTimeout = 500
 70→                };
 71→
 72→                _port.DataReceived += Port_DataReceived;
 73→                _port.Open();
 74→
 75→                Log?.Invoke($"[{_name}] Connected - {portName} @ {baudRate}");
 76→                return true;
 77→            }
 78→            catch (Exception ex)
 79→            {
 80→                Log?.Invoke($"[{_name}] Failed to open {portName}: {ex.Message}");
 81→                return false;
 82→            }
 83→        }
 84→
 85→        /// <summary>
 86→        /// 시리얼 데이터 수신 이벤트 (ThreadPool 쓰레드에서 실행)
 87→        /// RI 시리즈 Standard Stream 모드: "ST,NT,+01234.5\r\n" (16바이트)
 88→        /// ReadExisting + 라인 버퍼링 방식으로 프레임 동기화 보장
 89→        /// </summary>
 90→        private void Port_DataReceived(object sender, SerialDataReceivedEventArgs e)
 91→        {
 92→            try
 93→            {
 94→                if (_port == null || !_port.IsOpen) return;
 95→
 96→                // 수신된 데이터를 버퍼에 누적
 97→                _receiveBuffer += _port.ReadExisting();
 98→
 99→                // 완성된 라인(\n 기준)을 모두 처리, 마지막 완성 라인만 파싱
100→                int lastNewline = _receiveBuffer.LastIndexOf('\n');
101→                if (lastNewline < 0) return; // 완성된 라인 없음
102→
103→                // 완성된 라인들 추출
104→                string completed = _receiveBuffer.Substring(0, lastNewline + 1);
105→                // 미완성 데이터는 버퍼에 유지
106→                _receiveBuffer = _receiveBuffer.Substring(lastNewline + 1);
107→
108→                // 마지막 완성 라인만 파싱 (최신값)
109→                string[] lines = completed.Split('\n');
110→                for (int i = lines.Length - 1; i >= 0; i--)
111→                {
112→                    string data = lines[i].TrimEnd('\r', '\n');
113→                    if (data.Length >= 14 && data.StartsWith("ST,"))
114→                    {
115→                        string status = data.Substring(3, 2); // NT 또는 ER
116→
117→                        if (status == "NT")
118→                        {
119→                            string valueStr = data.Substring(6, 8);
120→                            if (double.TryParse(valueStr, out double val))
121→                            {
122→                                Value = val;
123→                                IsError = false;
124→                            }
125→                        }
126→                        else if (status == "ER")
127→                        {
128→                            IsError = true;
129→                        }
130→                        break; // 최신 유효 라인 하나만 처리
131→                    }
132→                }
133→            }
134→            catch
135→            {
136→                // 파싱 실패 시 무시 (기존값 유지)
137→            }
138→        }
139→
140→        /// <summary>
141→        /// 포트 닫기
142→        /// </summary>
143→        public void Close()
144→        {
145→            if (_port != null)
146→            {
147→                try
148→                {
149→                    _port.DataReceived -= Port_DataReceived;
150→                    if (_port.IsOpen)
151→                        _port.Close();
152→                    _port.Dispose();
153→                    Log?.Invoke($"[{_name}] Closed");
154→                }
155→                catch (Exception ex)
156→                {
157→                    Log?.Invoke($"[{_name}] Close error: {ex.Message}");
158→                }
159→                _port = null;
160→            }
161→        }
162→
163→        public void Dispose()
164→        {
165→            if (!_disposed)
166→            {
167→                Close();
168→                _disposed = true;
169→            }
170→        }
171→    }
172→}
