  1→using System;
  2→using System.IO.Ports;
  3→using System.Linq;
  4→using System.Text;
  5→using System.Threading;
  6→
  7→public sealed class ScannerStandard : IDisposable
  8→{
  9→    private readonly SerialPort _port;
 10→    private readonly Action<string> _log;
 11→    private volatile bool _running;
 12→    private readonly StringBuilder _rxBuffer = new StringBuilder(256);
 13→
 14→    public bool EnableLog { get; set; } = true;
 15→    public int ScannerId { get; }
 16→
 17→    // 이벤트
 18→    public event Action<string> DataReceived; // 스캔 데이터 수신
 19→
 20→    public ScannerStandard(SerialPort port, int scannerId = 1, Action<string> logger = null)
 21→    {
 22→        if (port == null)
 23→            throw new ArgumentNullException(nameof(port));
 24→        if (scannerId < 1 || scannerId > 2)
 25→            throw new ArgumentOutOfRangeException(nameof(scannerId), "ScannerId는 1~2");
 26→
 27→        ScannerId = scannerId;
 28→        _log = logger;
 29→        _port = port;
 30→
 31→        // 포트 설정
 32→        _port.BaudRate = 9600;
 33→        _port.Parity = Parity.None;
 34→        _port.DataBits = 8;
 35→        _port.StopBits = StopBits.One;
 36→        _port.Encoding = Encoding.ASCII;
 37→        _port.NewLine = "\r\n";
 38→        _port.ReadTimeout = 1000;
 39→        _port.WriteTimeout = 1000;
 40→        
 41→        // 인터럽트 방식: DataReceived 이벤트 사용
 42→        _port.DataReceived += OnDataReceived;
 43→    }
 44→
 45→    public void Start()
 46→    {
 47→        if (_running) return;
 48→
 49→        try
 50→        {
 51→            if (!_port.IsOpen)
 52→                _port.Open();
 53→        }
 54→        catch (Exception ex)
 55→        {
 56→            Log($"Scanner[{ScannerId}] 포트 열기 실패: {ex.Message}");
 57→            return;
 58→        }
 59→
 60→        _running = true;
 61→        _rxBuffer.Clear();
 62→        Log($"Scanner[{ScannerId}] 시작 (9600bps, {_port.PortName}, 인터럽트 방식)");
 63→    }
 64→
 65→    public void Stop()
 66→    {
 67→        _running = false;
 68→        Log($"Scanner[{ScannerId}] 통신 중지");
 69→    }
 70→
 71→    public void Dispose()
 72→    {
 73→        try
 74→        {
 75→            _port.DataReceived -= OnDataReceived;
 76→        }
 77→        catch { }
 78→        Stop();
 79→    }
 80→
 81→    // 인터럽트 방식: DataReceived 이벤트 핸들러
 82→    private void OnDataReceived(object sender, SerialDataReceivedEventArgs e)
 83→    {
 84→        if (!_running || !_port.IsOpen) return;
 85→
 86→        try
 87→        {
 88→            string chunk = _port.ReadExisting();
 89→            if (string.IsNullOrEmpty(chunk)) return;
 90→
 91→            // 바이너리 데이터 확인 (인쇄 불가능한 문자 포함 여부)
 92→            // CR(0x0D), LF(0x0A)는 정상적인 라인 종료 문자이므로 제외
 93→            bool hasControlChars = chunk.Any(c => char.IsControl(c) && c != '\r' && c != '\n');
 94→            if (hasControlChars)
 95→            {
 96→                string hex = string.Join(" ", chunk.Select(c => ((byte)c).ToString("X2")));
 97→                Log($"Scanner[{ScannerId}] 바이너리 데이터 수신 (무시): {hex}");
 98→                // 바이너리 데이터는 버퍼에 추가하지 않고 무시
 99→                _rxBuffer.Clear(); // 버퍼도 비워서 다음 데이터와 섞이지 않도록
100→                return;
101→            }
102→
103→            _rxBuffer.Append(chunk);
104→
105→            // CR/LF 기준으로 라인 파싱
106→            while (true)
107→            {
108→                int crlfIdx = _rxBuffer.ToString().IndexOf("\r\n", StringComparison.Ordinal);
109→                if (crlfIdx < 0) break;
110→
111→                string line = _rxBuffer.ToString(0, crlfIdx).Trim();
112→                _rxBuffer.Remove(0, crlfIdx + 2);
113→
114→                if (!string.IsNullOrWhiteSpace(line))
115→                {
116→                    DataReceived?.Invoke(line);
117→                }
118→            }
119→        }
120→        catch (Exception ex)
121→        {
122→            Log($"Scanner[{ScannerId}] 수신 오류: {ex.Message}");
123→            _rxBuffer.Clear(); // 오류 시 버퍼 비우기
124→        }
125→    }
126→
127→    private void Log(string s)
128→    {
129→        if (EnableLog && _log != null)
130→            _log(s);
131→    }
132→}
